sql:
SELECT bike_model 
FROM bikes 
WHERE bike_id = (
  SELECT MAX(bike_id) 
  FROM bikes
);

SELECT DISTINCT bike_id
FROM maintenance_logs
WHERE maintenance_cost > (SELECT AVG(maintenance_cost) FROM maintenance_logs);

SELECT trip_id, tripduration, starttime, usertype, weather_conditions, traffic_conditions
FROM trips
WHERE starttime LIKE '2023-04-01%' AND starttime LIKE '2023-04-01 0[0-6]:%:%';

